[Route("api/[controller]")]
public class TicketController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = predictionPool.Predict(input);

        // Extract the actual label order from the model's output schema
        var labelNames = GetLabelNames();
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < labelNames.Length; i++)
            confidence[labelNames[i]] = prediction.Score[i];

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    private string[] GetLabelNames()
    {
        var engine = predictionPool.GetPredictionEngine();
        try
        {
            var schema = engine.OutputSchema;
            var labelColumn = schema["PredictedLabel"];
            var slotNames = new VBuffer<ReadOnlyMemory<char>>();
            labelColumn.GetKeyValues(ref slotNames);
            return slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        }
        finally
        {
            predictionPool.ReturnPredictionEngine(engine);
        }
    }
}

