using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Stores the label names in the order used by the model's Score output.
/// </summary>
public class ModelMetadata
{
    public string[] Labels { get; set; } = [];
}

/// <summary>
/// Trains the ticket classification model at startup and saves it to disk.
/// </summary>
public class ModelTrainingService(
    ILogger<ModelTrainingService> logger,
    ModelMetadata metadata) : IHostedService
{
    public const string ModelPath = "Data/model.zip";

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Combine text features and normalize priority
        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Extract label names in key order from the trained model output
        var transformedData = model.Transform(split.TrainSet);
        var labelColumn = transformedData.Schema["Label"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        labelColumn.GetKeyValues(ref slotNames);
        metadata.Labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
        logger.LogInformation("Label order: {Labels}", string.Join(", ", metadata.Labels));

        // Evaluate on the held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        logger.LogInformation("=== Model Evaluation Metrics ===");
        logger.LogInformation("Macro Accuracy:   {MacroAccuracy:F4}", metrics.MacroAccuracy);
        logger.LogInformation("Micro Accuracy:   {MicroAccuracy:F4}", metrics.MicroAccuracy);
        logger.LogInformation("Log Loss:         {LogLoss:F4}", metrics.LogLoss);
        logger.LogInformation("Log Loss Reduction:{LogLossReduction:F4}", metrics.LogLossReduction);
        logger.LogInformation("Confusion Matrix:\n{Matrix}", metrics.ConfusionMatrix.GetFormattedConfusionTable());

        var savePath = Path.Combine(AppContext.BaseDirectory, ModelPath);
        mlContext.Model.Save(model, data.Schema, savePath);
        logger.LogInformation("Model saved to {Path}", savePath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

